trigger.body:
	vAmount NUMBER;
BEGIN
	IF UPDATING THEN
		SELECT SUM(amount) INTO vAmount FROM sspitra_ct_detail WHERE sspitra_collectiontransit_id=:NEW.sspitra_collectiontransit_id;
		UPDATE sspitra_collectiontransit SET amount=vAmount WHERE sspitra_collectiontransit_id=:NEW.sspitra_collectiontransit_id;
	END IF;

END SSPITRA_CT_DETAIL_AFTER_TRG
